// Add to compareExecutions function after calculating tests array:
interface TestComparisonItem { testSignature: string testName: string testFile: string baselineStatus: string | null currentStatus: string | null baselineDurationMs: number | null currentDurationMs: number | null durationDeltaMs: number | null durationDeltaPercent: number | null diffCategory: 'new_failure' | 'fixed' | 'new_test' | 'removed_test' | 'unchanged' durationCategory: 'regression' | 'improvement' | 'stable' | null // NEW }
// In SQL query, add: CASE WHEN b.test_signature IS NULL THEN NULL WHEN c.test_signature IS NULL THEN NULL WHEN b.duration_ms IS NULL OR b.duration_ms = 0 THEN NULL WHEN ((c.duration_ms - b.duration_ms)::float / b.duration_ms * 100) > ${regressionThreshold} THEN 'regression' WHEN ((c.duration_ms - b.duration_ms)::float / b.duration_ms * 100) < -${improvementThreshold} THEN 'improvement' ELSE 'stable' END as "durationCategory"

solution.updated_tool_definition:
{
  name: "compare_executions",
  description: `Compare two test executions to identify regressions, improvements, and changes.

Returns:
- baseline, current: Execution metadata
- summary: Pass rate delta, duration delta, status change counts
- performanceSummary: Count of duration regressions/improvements (NEW)
- tests: Array of test comparisons with diff and duration categories

Diff Categories: new_failure, fixed, new_test, removed_test, unchanged
Duration Categories: regression (>threshold% slower), improvement (<-threshold% faster), stable

Use filter param to focus on specific categories.`,
  inputSchema: {
    type: "object" as const,
    properties: {
      baseline_id: { type: "number", description: "Baseline execution ID (the 'before' run)" },
      current_id: { type: "number", description: "Current execution ID (the 'after' run)" },
      baseline_branch: { type: "string", description: "Use latest execution from this branch as baseline" },
      current_branch: { type: "string", description: "Use latest execution from this branch as current" },
      suite: { type: "string", description: "Filter to specific suite (applies to branch lookups)" },
      filter: {
        type: "string",
        enum: ["new_failure", "fixed", "new_test", "removed_test", "performance_regression", "all"],
        description: "Filter results by category (default: all)",
      },
      performance_threshold: {
        type: "number",
        default: 20,
        description: "Percentage change threshold for regression/improvement (default: 20%)",
      },
    },
  },
}

solution.updated_handler:
case "compare_executions": {
  const input = z.object({
    baseline_id: z.number().optional(),
    current_id: z.number().optional(),
    baseline_branch: z.string().optional(),
    current_branch: z.string().optional(),
    suite: z.string().optional(),
    filter: z.enum(["new_failure", "fixed", "new_test", "removed_test", "performance_regression", "all"]).optional(),
    performance_threshold: z.number().min(1).max(100).default(20),
  }).parse(args)

  // ... existing ID resolution logic ...

  const comparison = await db.compareExecutions(
    orgId, 
    baselineId, 
    currentId,
    { performanceThreshold: input.performance_threshold }
  )

  // Apply filter including new performance_regression option
  let filteredTests = comparison.tests
  if (input.filter === "performance_regression") {
    filteredTests = comparison.tests.filter((t) => t.durationCategory === "regression")
  } else if (input.filter && input.filter !== "all") {
    filteredTests = comparison.tests.filter((t) => t.diffCategory === input.filter)
  }

  // Calculate performance summary
  const performanceSummary = {
    regressions: comparison.tests.filter((t) => t.durationCategory === "regression").length,
    improvements: comparison.tests.filter((t) => t.durationCategory === "improvement").length,
    stable: comparison.tests.filter((t) => t.durationCategory === "stable").length,
    threshold_pct: input.performance_threshold,
  }

  return jsonResponse({
    organization: authContext.organizationSlug,
    baseline: comparison.baseline,
    current: comparison.current,
    summary: comparison.summary,
    performanceSummary,  // NEW
    filter: input.filter || "all",
    tests: filteredTests,
    test_count: filteredTests.length,
  })
}
